// marked.js vendor placeholder.
//
// STUB. The real bundle (marked, ~40 KB) exposes window.marked.parse(md)
// → HTML. This placeholder implements a deliberately tiny Markdown subset
// (escaped text + paragraphs + `code`) so summary/AI-explanation text is
// at least readable without the real bundle, and warns once. Replace with
// the upstream bundle (see README.md) for full CommonMark.

(function () {
  if (typeof window === 'undefined') return;
  if (window.__topoMarkedPlaceholder) return;
  window.__topoMarkedPlaceholder = true;
  if (typeof console !== 'undefined' && console.warn) {
    console.warn(
      '[topo-debug] marked.min.js is a placeholder (tiny subset only). ' +
      'Drop the real marked bundle at ' +
      'topo-core/lib/Debug/Server/vendor/marked.min.js for full Markdown. ' +
      'See README.md in the same directory.'
    );
  }
  function esc(s) {
    return String(s).replace(/[&<>"']/g, function (c) {
      return ({ '&': '&amp;', '<': '&lt;', '>': '&gt;',
                '"': '&quot;', "'": '&#39;' })[c];
    });
  }
  function parse(md) {
    if (md == null) return '';
    return String(md)
      .split(/\n{2,}/)
      .map(function (p) {
        var h = esc(p).replace(/`([^`]+)`/g, '<code>$1</code>');
        return '<p>' + h.replace(/\n/g, '<br>') + '</p>';
      })
      .join('\n');
  }
  window.marked = { parse: parse };
})();
